class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        def is_palindrome(s: str) -> bool:
            return s == s[::-1]

        for i in range(len(a)):
            if is_palindrome(a[:i] + b[i:]) or is_palindrome(b[:i] + a[i:]):
                return True
        return False
